option.value:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Inter", sans-serif;
  text-decoration: none;
  list-style: none;
  scroll-behavior: smooth;
}

/* ===== Base & Theme Variables ===== */
:root {
  --text-color: #e5e5e5;
  --bg-color: #1a0f0f;
  --second-bg-color: #221515;
  --main-color: #8B0000;
  --other-color: #a1a1aa;
  --h1-font: 4rem;
  --h2-font: 2.8rem;
  --p-font: 1rem;
}

/* Light mode overrides */
body.light-mode {
  --text-color: #111111;
  --bg-color: #ffffff;
  --second-bg-color: #f3f3f3;
  --main-color: #8B0000;
  --other-color: #555555;
  /* gradient lebih cerah untuk light mode */
  background: linear-gradient(180deg, #ffffff 0%, #f3f3f3 100%);
}

/* ===== Global Layout ===== */
body {
  color: var(--text-color);
  background: linear-gradient(180deg, #1a0f0f 0%, #0f0f0f 100%);
}

/* ===== Header / Navbar ===== */
header {
  position: fixed;
  width: 100%;
  top: 0;
  right: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 30px 10%;
  background: transparent;
  transition: all 0.4s ease;
}
header.sticky {
  background: var(--bg-color);
  padding: 15px 10%;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}
.logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 24px;
  font-weight: 700;
  color: var(--text-color);
}
.logo-box {
  background: var(--main-color);
  color: #ffffff;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}
.navlist {
  display: flex;
}
.navlist a {
  font-size: var(--p-font);
  font-weight: 500;
  color: var(--text-color);
  margin: 0 18px;
  transition: 0.3s;
}
.navlist a:hover,
.navlist a.active {
  color: var(--main-color);
}
.header-btns {
  display: flex;
  align-items: center;
  gap: 15px;
}
.h-btn {
  padding: 10px 22px;
  border-radius: 8px;
  border: 1.5px solid var(--main-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 500;
  background: transparent;
  transition: 0.3s;
}
.h-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.theme-toggle {
  font-size: 22px;
  cursor: pointer;
  color: var(--text-color);
  transition: 0.3s;
}
.theme-toggle:hover {
  color: var(--main-color);
  transform: scale(1.05);
}
#menu-icon {
  font-size: 32px;
  cursor: pointer;
  display: none;
  color: var(--text-color);
}

/* ===== Sections & Containers ===== */
section {
  padding: 120px 10% 80px;
}

/* tambahkan container global untuk halaman seperti portfolio, blog, repository */
.page-content {
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}

/* ===== Hero (Index) ===== */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
}


.hero-wrapper {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  align-items: center;
  gap: 40px;
}
.welcome-badge {
  display: inline-block;
  padding: 4px 16px;
  border-radius: 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  font-size: 0.8rem;
  font-weight: 600;
  margin-bottom: 18px;
}
.hero-text h1 {
  font-size: var(--h1-font);
  line-height: 1.1;
  margin-bottom: 18px;
}
.hero-text h1 span {
  color: var(--main-color);
}
.hero-text p {
  font-size: var(--p-font);
  color: var(--other-color);
  line-height: 1.7;
  max-width: 520px;
  margin-bottom: 30px;
}
.hero-btns {
  display: flex;
  align-items: center;
  gap: 25px;
}
.btn {
  padding: 13px 28px;
  border-radius: 10px;
  background: var(--main-color);
  color: #ffffff;
  font-size: 0.95rem;
  font-weight: 600;
  transition: 0.3s;
}
.btn:hover {
  opacity: 0.85;
  transform: translateY(-2px);
}
.view-work {
  color: var(--text-color);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* hero image side */
.hero-img {
  position: relative;
  display: flex;
  justify-content: center;
}
.img-container {
  position: relative;
  width: 360px;
  height: 410px;
  z-index: 5;
}
.img-container img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  background: var(--main-color);
}
.img-outline {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 3px solid var(--text-color);
  top: 28px;
  left: -28px;
  z-index: -1;
}
.social-float {
  position: absolute;
  right: -60px;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 18px;
}
.social-float p {
  writing-mode: vertical-rl;
  font-size: 13px;
  color: var(--other-color);
  letter-spacing: 1px;
}
.social-float a {
  color: var(--main-color);
  font-size: 20px;
}

/* ===== Stats ===== */
.stat-item h2 {
  font-size: clamp(2.2rem, 4.5vw, 3.5rem);
  color: var(--main-color);
}

/* ===== Cards & Grids ===== */
.box-grid,
.services-content,
.Portfolio-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, auto));
  gap: 2rem;
}
.card,
.box,
.row {
  background: var(--second-bg-color);
  border-radius: 20px;
  padding: 40px 28px;
  transition: 0.4s;
}

/* --- Skills section (rectangle cards) from index inline CSS --- */
.skills-container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 20px;
  margin-top: 2rem;
}

.skill-card-rect {
  display: flex;
  align-items: center;
  padding: 18px 25px;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 51, 51, 0.1);
  border-radius: 16px;
  transition: all 0.4s ease;
  gap: 15px;
}

.skill-card-rect:hover {
  transform: translateX(10px);
  border-color: var(--main-color);
  background: rgba(139, 0, 0, 0.05);
  box-shadow: -5px 0 20px rgba(139, 0, 0, 0.15);
}

.skill-icon {
  font-size: 28px;
  color: var(--main-color);
  background: rgba(255, 255, 255, 0.03);
  width: 45px;
  height: 45px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
}

.skill-info h4 {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-color);
}

.skill-info p {
  font-size: 0.8rem;
  color: var(--other-color);
}

/* ===== Contact (Index) ===== */
.contact {
  padding: 100px 10% 120px;
  display: flex;
  justify-content: flex-start;
}

.contact-container {
  max-width: 800px;
}

.contact-container h2 {
  font-size: 2.5rem;
  font-weight: 600;
  margin-bottom: 50px;
  color: var(--text-color);
}

.contact-container p {
  color: var(--text-color);
  line-height: 1.6;
  margin-bottom: 30px;
  font-size: 1.1rem;
  max-width: 700px;
}

.contact-email {
  display: block;
  color: var(--text-color);
  font-weight: 500;
  font-size: 1.2rem;
  margin-bottom: 40px;
  transition: 0.3s;
}

.contact-email:hover {
  color: var(--main-color);
}

.social-links-minimal {
  display: flex;
  gap: 25px;
  align-items: center;
}

.social-links-minimal a {
  font-size: 24px;
  color: var(--text-color);
  transition: 0.3s ease;
}

.social-links-minimal a:hover {
  color: var(--main-color);
  transform: translateY(-5px);
}

/* Divider section from index */
.section-divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 51, 51, 0.3), transparent);
  margin: 2rem 0;
}

/* Light Mode Support for skills card (moved from inline) */
body.light-mode .skill-card-rect {
  background: #ffffff;
  border-color: #eee;
}

/* ===== Footer ===== */
.footer {
  padding: 40px 10%;
  text-align: center;
  background: var(--second-bg-color);
  color: var(--other-color);
  margin-top: 40px;
}

/* override khusus untuk card / blog di light mode */
body.light-mode .card,
body.light-mode .box,
body.light-mode .row,
body.light-mode .portfolio-card,
body.light-mode .cert-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card::before {
  background: radial-gradient(circle, rgba(139, 0, 0, 0.07) 0%, transparent 60%);
}

/* ===== Portfolio ===== */
.portfolio-container {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 40px;
}
.portfolio-card {
  background: rgba(255,255,255,0.02);
  border-radius: 30px;
  border: 1px solid rgba(255,255,255,0.08);
  display: grid;
  grid-template-columns: 1fr 1fr;
  overflow: hidden;
  transition: 0.4s;
}
.portfolio-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 18px 38px rgba(0,0,0,0.35);
}
.card-info {
  padding: 50px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.card-tag {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--other-color);
  margin-bottom: 12px;
}
.card-info h2 {
  font-size: 2rem;
  margin-bottom: 18px;
}
.card-info ul {
  margin-bottom: 25px;
}
.card-info ul li {
  color: var(--other-color);
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.card-info ul li i {
  color: var(--main-color);
}
.view-case-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 22px;
  border-radius: 10px;
  background: #ffffff;
  color: #000000;
  font-weight: 600;
  font-size: 0.9rem;
  transition: 0.3s;
}
.view-case-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.card-img {
  padding: 35px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(circle at top, rgba(255,51,51,0.15), transparent 60%);
}
.card-img img {
  width: 100%;
  height: 330px;
  object-fit: cover;
  border-radius: 20px;
}

/* ===== CV ===== */
.cv-container {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 40px;
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}
.cv-sidebar {
  position: sticky;
  top: 120px;
  height: fit-content;
}
.cv-sidebar ul li {
  margin-bottom: 14px;
}
.cv-sidebar ul li a {
  color: var(--other-color);
  font-size: 0.9rem;
  font-weight: 500;
  padding: 8px 14px;
  border-left: 2px solid transparent;
  display: block;
  transition: 0.3s;
}
.cv-sidebar ul li a:hover {
  color: var(--main-color);
  border-left-color: var(--main-color);
  /* Background hover lebih halus dengan tint merah */
  background: rgba(139, 0, 0, 0.1);
  border-radius: 0 8px 8px 0;
}
.cv-content {
  /* Gradasi Gelap ke Merah Sangat Tua (Night Mode) */
  background: linear-gradient(145deg, rgba(34, 21, 21, 0.9) 0%, rgba(15, 10, 10, 0.95) 100%);
  border-radius: 24px;
  /* Border merah transparan agar terlihat 'menyala' tipis */
  border: 1px solid rgba(139, 0, 0, 0.3);
  padding: 50px;
  /* Shadow merah halus untuk kedalaman */
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5), 0 0 15px rgba(139, 0, 0, 0.05);
  backdrop-filter: blur(10px);
}
.cv-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 35px;
  padding-bottom: 25px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
}
.cv-header h1 {
  font-size: 2.6rem;
  margin-bottom: 8px;
}
.cv-header p {
  color: var(--main-color);
  font-weight: 600;
}
.pdf-icon {
  font-size: 36px;
  color: var(--main-color);
  cursor: pointer;
}
.cv-section {
  margin-bottom: 40px;
}
.cv-section h2 {
  font-size: 1.7rem;
  margin-bottom: 20px;
  padding-left: 12px;
  border-left: 4px solid var(--main-color);
}
.basics-grid {
  display: grid;
  grid-template-columns: 150px 1fr;
  gap: 15px;
  /* Warna kotak info dasar: Putih transparan dengan tint merah */
  background: rgba(255, 255, 255, 0.03);
  padding: 25px;
  border-radius: 15px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}

body.light-mode .cv-sidebar ul li a:hover {
  background: rgba(139, 0, 0, 0.05);
}

body.light-mode .basics-grid {
  /* Kotak info di light mode: Merah pucat bersih */
  background: rgba(139, 0, 0, 0.02);
  border: 1px solid rgba(139, 0, 0, 0.08);
}

/* Penyesuaian Light Mode untuk CV */
body.light-mode .cv-content {
  /* Gradasi Putih ke Merah Sangat Muda */
  background: linear-gradient(145deg, #ffffff 0%, #fff5f5 100%);
  border: 1px solid rgba(139, 0, 0, 0.1);
  box-shadow: 0 20px 40px rgba(139, 0, 0, 0.05);
  color: #111;
}

.cv-sidebar ul li a {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.cv-content h2 {
  /* Memberikan sedikit glow pada judul section */
  text-shadow: 0 0 10px rgba(139, 0, 0, 0.2);
}

.basics-grid span:nth-child(odd) {
  font-weight: 600;
  color: var(--other-color);
}
.timeline-item {
  margin-bottom: 26px;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
}
.timeline-title {
  font-weight: 700;
}
.timeline-subtitle {
  color: var(--main-color);
  font-size: 0.95rem;
  margin-bottom: 6px;
  display: block;
}
/* Timeline Badge (Date) */
.timeline-date {
  background: var(--main-color); /* Merah marun kamu */
  color: #ffffff;               /* Ganti dari hitam ke putih */
  padding: 4px 14px;            /* Sedikit lebih lebar agar lega */
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 700;             /* Tebalkan sedikit agar makin jelas */
  display: inline-block;
  box-shadow: 0 4px 12px rgba(139, 0, 0, 0.3); /* Shadow merah halus */
  letter-spacing: 0.5px;
}

/* Jika ingin transisi halus saat hover */
.timeline-item:hover .timeline-date {
  transform: scale(1.05);
  transition: 0.3s;
}

.timeline-content {
  color: var(--other-color);
  font-size: 0.9rem;
}
.timeline-content li {
  margin-left: 18px;
  list-style: disc;
  margin-bottom: 5px;
}
.skills-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}
.skill-cat h4 {
  margin-bottom: 10px;
  color: var(--main-color);
}
.skill-list {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* ===== Certifications ===== */
.cert-header {
  text-align: center;
  margin-bottom: 60px;
}
.cert-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.cert-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.cert-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 24px;
  max-width: 1200px;
  margin: 0 auto;
}
.cert-card {
  background: rgba(255,255,255,0.02);
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.15);
  padding: 26px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: 0.3s;
}
.cert-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 16px 32px rgba(0,0,0,0.3);
}
.cert-img-box {
  width: 100%;
  height: 200px;
  border-radius: 16px;
  overflow: hidden;
  background: var(--second-bg-color);
}
.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: 0.4s;
}
.cert-card:hover .cert-img-box img {
  transform: scale(1.05);
}
.cert-info h3 {
  font-size: 1.4rem;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.cert-info h3 i {
  color: var(--main-color);
}
.cert-info p {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* ===== Blog ===== */
.blog-header {
  text-align: center;
  margin-bottom: 60px;
}
.blog-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.blog-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.blog-header p {
  color: var(--other-color);
}
.blog-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 26px;
  max-width: 1200px;
  margin: 0 auto;
}
.blog-card {
  background: #130b0b;
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.18);
  padding: 38px;
  min-height: 320px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  position: relative;
  overflow: hidden;
  transition: 0.35s;
}
.blog-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,51,51,0.06) 0%, transparent 60%);
}
.blog-card h2 {
  font-size: 1.7rem;
  line-height: 1.3;
}
.blog-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 20px 40px rgba(0,0,0,0.35);
}
.blog-card:hover h2 {
  color: var(--main-color);
}
.blog-icon {
  width: 46px;
  height: 46px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}

/* ===== Search Modal ===== */
.search-modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.8);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 1200;
}
.search-modal.active {
  display: flex;
}
.search-box {
  background: #1a1a1a;
  padding: 20px;
  border-radius: 12px;
  width: 90%;
  max-width: 420px;
}
.search-box input {
  width: 100%;
  padding: 10px 12px;
  border-radius: 6px;
  border: none;
  outline: none;
  margin-bottom: 12px;
}
.search-box ul li {
  margin-bottom: 6px;
}
.search-box ul li a {
  color: #ffffff;
  font-size: 0.95rem;
}

/* agar modal ikut light mode */
body.light-mode .search-box {
  background: #ffffff;
}
body.light-mode .search-box input {
  background: #f3f3f3;
  color: #111111;
}
body.light-mode .search-box ul li a {
  color: #111111;
}

/* =========================
   REPOSITORY PAGE STYLES
   ========================= */

.github-btn-center {
  display: flex;
  justify-content: center;
  margin-bottom: 60px;
}
.gh-profile-btn {
  padding: 12px 25px;
  background: var(--second-bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  color: var(--text-color);
  border-radius: 30px;
  font-size: 14px;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 10px;
  transition: 0.3s;
}
.gh-profile-btn:hover {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* filter & search bar di halaman repository */
.repo-filters {
  background: var(--second-bg-color);
  padding: 30px;
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  align-items: center;
  margin-bottom: 50px;
}
.repo-filters .search-input {
  flex: 1;
  min-width: 250px;
  background: var(--bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 12px 20px;
  border-radius: 12px;
  color: var(--text-color);
  outline: none;
}
.repo-filters .filter-select {
  padding: 12px 15px;
  background: var(--bg-color);
  color: var(--text-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  border-radius: 12px;
  outline: none;
}
.repo-filters .reset-btn {
  padding: 12px 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
  display: flex;
  align-items: center;
  gap: 6px;
}
.repo-filters .reset-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}

/* repo grid / cards */
.repo-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 25px;
}
.repo-card {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 30px;
  transition: 0.4s;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  min-height: 220px;
}
.repo-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 15px 30px rgba(255, 51, 51, 0.1);
}
.repo-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 1.1rem;
  font-weight: 700;
  margin-bottom: 15px;
  color: var(--text-color);
}
.repo-title i {
  color: var(--main-color);
}
.repo-desc {
  font-size: 14px;
  color: var(--other-color);
  line-height: 1.6;
  margin-bottom: 25px;
}
.repo-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  color: var(--other-color);
}
.lang-tag {
  padding: 4px 10px;
  background: var(--main-color);
  color: #ffffff;
  border-radius: 6px;
  font-weight: 700;
  font-size: 10px;
}

/* certification filters */
.cert-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  justify-content: center;
  margin: 20px 0 40px;
}

.filter-tag {
  padding: 10px 18px;
  border-radius: 999px;
  border: 1px solid rgba(255, 51, 51, 0.2);
  background: var(--second-bg-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
}

.filter-tag:hover,
.filter-tag.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* pagination buttons (certs + repo) */
.pagination-container {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin: 30px 0 10px;
}

.page-btn {
  min-width: 40px;
  height: 40px;
  padding: 0 14px;
  border-radius: 10px;
  border: 1px solid rgba(255, 51, 51, 0.2);
  background: var(--second-bg-color);
  color: var(--text-color);
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
}

.page-btn:hover,
.page-btn.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* light mode */
body.light-mode .filter-tag,
body.light-mode .page-btn {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.08);
  color: #111111;
}

body.light-mode .filter-tag:hover,
body.light-mode .filter-tag.active,
body.light-mode .page-btn:hover,
body.light-mode .page-btn.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* ===== Responsive ===== */
html {
  width: 100%;
  overflow-x: hidden;
}

body {
  width: 100%;
  overflow-x: hidden;
  line-height: 1.6;
}

img,
svg,
video {
  max-width: 100%;
  height: auto;
  display: block;
}

:where(section, .page-content, .cv-container) {
  width: 100%;
}

section {
  padding: clamp(90px, 10vw, 120px) clamp(4vw, 8vw, 10%) clamp(50px, 6vw, 80px);
}

.page-content,
.cv-container {
  padding-inline: clamp(4vw, 8vw, 10%);
}

.page-content {
  padding-top: clamp(110px, 12vw, 150px);
  max-width: 1400px;
  margin: 0 auto;
}

/* shared page headers */
.page-header,
.blog-header,
.cert-header,
.repo-header {
  text-align: center;
  margin-bottom: clamp(30px, 5vw, 60px);
}

.page-header h1,
.blog-header h1,
.cert-header h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  line-height: 1.1;
}

.page-header p,
.blog-header p,
.cert-header p {
  color: var(--other-color);
  max-width: 720px;
  margin: 0 auto;
}

/* navbar */
header,
header.sticky {
  padding-inline: clamp(16px, 4vw, 10%);
}

.logo {
  font-size: clamp(18px, 2vw, 24px);
}

.logo-box {
  width: 36px;
  height: 36px;
  font-size: 20px;
}

.navlist a {
  margin: 0 14px;
  white-space: nowrap;
}

.header-btns {
  gap: 12px;
}

.search-trigger {
  padding: 6px 12px;
  white-space: nowrap;
}

/* hero */
.hero {
  min-height: 100vh;
  padding-top: 120px;
}

.hero-wrapper {
  grid-template-columns: minmax(0, 1.15fr) minmax(0, 0.85fr);
  gap: clamp(24px, 4vw, 40px);
}

.hero-text h1 {
  font-size: clamp(2.4rem, 5vw, 4rem);
}

.hero-text p {
  max-width: 60ch;
}

.img-container {
  width: min(100%, 360px);
  aspect-ratio: 360 / 410;
  height: auto;
}

.img-outline {
  top: 24px;
  left: -24px;
}

.hero-stats {
  gap: 24px;
  flex-wrap: wrap;
}

/* grids/cards */
.box-grid,
.services-content,
.Portfolio-content,
.skills-container,
.cert-grid,
.blog-grid,
.repo-grid,
.skills-grid {
  width: 100%;
}

.box-grid,
.services-content,
.Portfolio-content {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

.skills-container {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 240px), 1fr));
}

.cert-grid,
.blog-grid {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

.repo-grid {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

/* portfolio */
.portfolio-container {
  width: 100%;
  gap: clamp(24px, 4vw, 40px);
}

.portfolio-card {
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
}

.card-info {
  padding: clamp(28px, 5vw, 50px);
}

.card-img {
  padding: clamp(20px, 4vw, 35px);
}

.card-img img {
  height: clamp(240px, 30vw, 330px);
  object-fit: cover;
}

/* CV */
.cv-container {
  grid-template-columns: minmax(220px, 260px) minmax(0, 1fr);
  gap: clamp(20px, 4vw, 40px);
}

.cv-content {
  padding: clamp(24px, 4vw, 50px);
}

.basics-grid {
  grid-template-columns: minmax(120px, 180px) minmax(0, 1fr);
}

.skills-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 20px;
}

/* certifications / blog / repo */
.cert-card,
.blog-card,
.repo-card {
  min-width: 0;
}

.cert-img-box {
  width: 100%;
  height: 200px;
  background: #f8f8f8;
  border-radius: 12px;
  overflow: hidden;
  cursor: zoom-in;
}

.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  padding: 6px;
}

.blog-card {
  padding: clamp(24px, 4vw, 38px);
  min-height: 280px;
}

.repo-stats {
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 20px;
  max-width: 900px;
  padding: 0;
}

.repo-filters {
  padding: 24px;
}

.repo-filters .search-input {
  min-width: 0;
}

/* search / modal */
.search-box,
.modal-content {
  width: min(100%, 1000px);
}

.search-box {
  max-width: 420px;
}

.modal-body {
  padding: clamp(24px, 4vw, 50px);
}

.modal-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: clamp(20px, 4vw, 40px);
}

.tech-stack-container,
.tech-stack-img-container {
  flex-wrap: wrap;
}

.tech-logo-item {
  width: 42px;
  height: 42px;
}

/* footer */
.footer {
  padding-inline: clamp(16px, 4vw, 10%);
}

/* responsive breakpoints */
@media (max-width: 1200px) {
  .hero-wrapper {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-text p {
    margin-inline: auto;
  }

  .hero-btns {
    justify-content: center;
  }

  .hero-img {
    order: -1;
    margin-bottom: 30px;
  }

  .social-float {
    display: none;
  }

  .hero-stats {
    justify-content: center;
  }

  .cv-container {
    grid-template-columns: 1fr;
  }

  .cv-sidebar {
    position: static;
    top: auto;
  }
}

@media (max-width: 950px) {
  #menu-icon {
    display: block;
  }

  .header-btns {
    margin-left: auto;
  }

  .navlist {
    position: fixed;
    top: 76px;
    right: -100%;
    width: min(86vw, 320px);
    height: calc(100vh - 76px);
    background: var(--second-bg-color);
    flex-direction: column;
    padding: 26px 20px;
    transition: 0.35s ease;
    overflow-y: auto;
    border-left: 1px solid rgba(255, 51, 51, 0.12);
  }

  .navlist.active {
    right: 0;
  }

  .navlist a {
    display: block;
    margin: 8px 0;
    padding: 10px 12px;
    border-radius: 10px;
  }

  .navlist a.active,
  .navlist a:hover {
    background: rgba(139, 0, 0, 0.12);
  }

  .repo-stats {
    grid-template-columns: 1fr;
  }

  .modal-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  :root {
    --h1-font: 3rem;
    --h2-font: 2.2rem;
    --p-font: 0.98rem;
  }

  header,
  header.sticky {
    padding-block: 14px;
  }

  .hero {
    padding-top: 110px;
  }

  .hero-stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    width: 100%;
  }

  .skills-grid,
  .basics-grid {
    grid-template-columns: 1fr;
  }

  .portfolio-card {
    grid-template-columns: 1fr;
  }

  .page-content,
  .cv-container,
  section {
    padding-left: 16px;
    padding-right: 16px;
  }

  .repo-filters {
    flex-direction: column;
    align-items: stretch;
  }

  .repo-filters .search-input,
  .repo-filters .filter-select,
  .repo-filters .reset-btn {
    width: 100%;
  }
}

@media (max-width: 640px) {
  .hero-text h1 {
    font-size: clamp(2.1rem, 10vw, 3rem);
  }

  .hero-stats {
    grid-template-columns: 1fr;
  }

  .contact {
    padding: 80px 16px 100px;
  }

  .social-links-minimal {
    flex-wrap: wrap;
    gap: 16px;
  }

  .blog-card {
    min-height: 240px;
  }

  .cert-card,
  .repo-card {
    padding: 22px;
  }

  .pagination-container {
    flex-wrap: wrap;
  }
}

@media (max-width: 480px) {
  .logo {
    font-size: 18px;
  }

  .logo-box {
    width: 32px;
    height: 32px;
    font-size: 18px;
  }

  .search-trigger .search-kb {
    display: none;
  }

  .hero-btns {
    flex-direction: column;
    gap: 14px;
  }

  .btn,
  .view-case-btn,
  .h-btn {
    width: 100%;
    justify-content: center;
  }

  .modal-body {
    padding: 20px;
  }
}

/* duplicate cleanup applied:
   - removed early duplicate .cert-header with negative margin
   - removed later duplicate .cert-img-box block
   - unified .stat-item h2 to clamp size
*/

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Inter", sans-serif;
  text-decoration: none;
  list-style: none;
  scroll-behavior: smooth;
}

/* ===== Base & Theme Variables ===== */
:root {
  --text-color: #e5e5e5;
  --bg-color: #1a0f0f;
  --second-bg-color: #221515;
  --main-color: #8B0000;
  --other-color: #a1a1aa;
  --h1-font: 4rem;
  --h2-font: 2.8rem;
  --p-font: 1rem;
}

/* Light mode overrides */
body.light-mode {
  --text-color: #111111;
  --bg-color: #ffffff;
  --second-bg-color: #f3f3f3;
  --main-color: #8B0000;
  --other-color: #555555;
  /* gradient lebih cerah untuk light mode */
  background: linear-gradient(180deg, #ffffff 0%, #f3f3f3 100%);
}

/* ===== Global Layout ===== */
body {
  color: var(--text-color);
  background: linear-gradient(180deg, #1a0f0f 0%, #0f0f0f 100%);
}

/* ===== Header / Navbar ===== */
header {
  position: fixed;
  width: 100%;
  top: 0;
  right: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 30px 10%;
  background: transparent;
  transition: all 0.4s ease;
}
header.sticky {
  background: var(--bg-color);
  padding: 15px 10%;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}
.logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 24px;
  font-weight: 700;
  color: var(--text-color);
}
.logo-box {
  background: var(--main-color);
  color: #ffffff;
  width: 38px;
  height: 38px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}
.navlist {
  display: flex;
}
.navlist a {
  font-size: var(--p-font);
  font-weight: 500;
  color: var(--text-color);
  margin: 0 18px;
  transition: 0.3s;
}
.navlist a:hover,
.navlist a.active {
  color: var(--main-color);
}
.header-btns {
  display: flex;
  align-items: center;
  gap: 15px;
}
.h-btn {
  padding: 10px 22px;
  border-radius: 8px;
  border: 1.5px solid var(--main-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 500;
  background: transparent;
  transition: 0.3s;
}
.h-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.theme-toggle {
  font-size: 22px;
  cursor: pointer;
  color: var(--text-color);
  transition: 0.3s;
}
.theme-toggle:hover {
  color: var(--main-color);
  transform: scale(1.05);
}
#menu-icon {
  font-size: 32px;
  cursor: pointer;
  display: none;
  color: var(--text-color);
}

/* ===== Sections & Containers ===== */
section {
  padding: 120px 10% 80px;
}

/* tambahkan container global untuk halaman seperti portfolio, blog, repository */
.page-content {
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}

/* ===== Hero (Index) ===== */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
}


.hero-wrapper {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  align-items: center;
  gap: 40px;
}
.welcome-badge {
  display: inline-block;
  padding: 4px 16px;
  border-radius: 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  font-size: 0.8rem;
  font-weight: 600;
  margin-bottom: 18px;
}
.hero-text h1 {
  font-size: var(--h1-font);
  line-height: 1.1;
  margin-bottom: 18px;
}
.hero-text h1 span {
  color: var(--main-color);
}
.hero-text p {
  font-size: var(--p-font);
  color: var(--other-color);
  line-height: 1.7;
  max-width: 520px;
  margin-bottom: 30px;
}
.hero-btns {
  display: flex;
  align-items: center;
  gap: 25px;
}
.btn {
  padding: 13px 28px;
  border-radius: 10px;
  background: var(--main-color);
  color: #ffffff;
  font-size: 0.95rem;
  font-weight: 600;
  transition: 0.3s;
}
.btn:hover {
  opacity: 0.85;
  transform: translateY(-2px);
}
.view-work {
  color: var(--text-color);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* hero image side */
.hero-img {
  position: relative;
  display: flex;
  justify-content: center;
}
.img-container {
  position: relative;
  width: 360px;
  height: 410px;
  z-index: 5;
}
.img-container img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  background: var(--main-color);
}
.img-outline {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 3px solid var(--text-color);
  top: 28px;
  left: -28px;
  z-index: -1;
}
.social-float {
  position: absolute;
  right: -60px;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 18px;
}
.social-float p {
  writing-mode: vertical-rl;
  font-size: 13px;
  color: var(--other-color);
  letter-spacing: 1px;
}
.social-float a {
  color: var(--main-color);
  font-size: 20px;
}

/* ===== Stats ===== */
.stat-item h2 {
  font-size: clamp(2.2rem, 4.5vw, 3.5rem);
  color: var(--main-color);
}

/* ===== Cards & Grids ===== */
.box-grid,
.services-content,
.Portfolio-content {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, auto));
  gap: 2rem;
}
.card,
.box,
.row {
  background: var(--second-bg-color);
  border-radius: 20px;
  padding: 40px 28px;
  transition: 0.4s;
}

/* --- Skills section (rectangle cards) from index inline CSS --- */
.skills-container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 20px;
  margin-top: 2rem;
}

.skill-card-rect {
  display: flex;
  align-items: center;
  padding: 18px 25px;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 51, 51, 0.1);
  border-radius: 16px;
  transition: all 0.4s ease;
  gap: 15px;
}

.skill-card-rect:hover {
  transform: translateX(10px);
  border-color: var(--main-color);
  background: rgba(139, 0, 0, 0.05);
  box-shadow: -5px 0 20px rgba(139, 0, 0, 0.15);
}

.skill-icon {
  font-size: 28px;
  color: var(--main-color);
  background: rgba(255, 255, 255, 0.03);
  width: 45px;
  height: 45px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
}

.skill-info h4 {
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text-color);
}

.skill-info p {
  font-size: 0.8rem;
  color: var(--other-color);
}

/* ===== Contact (Index) ===== */
.contact {
  padding: 100px 10% 120px;
  display: flex;
  justify-content: flex-start;
}

.contact-container {
  max-width: 800px;
}

.contact-container h2 {
  font-size: 2.5rem;
  font-weight: 600;
  margin-bottom: 50px;
  color: var(--text-color);
}

.contact-container p {
  color: var(--text-color);
  line-height: 1.6;
  margin-bottom: 30px;
  font-size: 1.1rem;
  max-width: 700px;
}

.contact-email {
  display: block;
  color: var(--text-color);
  font-weight: 500;
  font-size: 1.2rem;
  margin-bottom: 40px;
  transition: 0.3s;
}

.contact-email:hover {
  color: var(--main-color);
}

.social-links-minimal {
  display: flex;
  gap: 25px;
  align-items: center;
}

.social-links-minimal a {
  font-size: 24px;
  color: var(--text-color);
  transition: 0.3s ease;
}

.social-links-minimal a:hover {
  color: var(--main-color);
  transform: translateY(-5px);
}

/* Divider section from index */
.section-divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255, 51, 51, 0.3), transparent);
  margin: 2rem 0;
}

/* Light Mode Support for skills card (moved from inline) */
body.light-mode .skill-card-rect {
  background: #ffffff;
  border-color: #eee;
}

/* ===== Footer ===== */
.footer {
  padding: 40px 10%;
  text-align: center;
  background: var(--second-bg-color);
  color: var(--other-color);
  margin-top: 40px;
}

/* override khusus untuk card / blog di light mode */
body.light-mode .card,
body.light-mode .box,
body.light-mode .row,
body.light-mode .portfolio-card,
body.light-mode .cert-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.06);
}

body.light-mode .blog-card::before {
  background: radial-gradient(circle, rgba(139, 0, 0, 0.07) 0%, transparent 60%);
}

/* ===== Portfolio ===== */
.portfolio-container {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 40px;
}
.portfolio-card {
  background: rgba(255,255,255,0.02);
  border-radius: 30px;
  border: 1px solid rgba(255,255,255,0.08);
  display: grid;
  grid-template-columns: 1fr 1fr;
  overflow: hidden;
  transition: 0.4s;
}
.portfolio-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 18px 38px rgba(0,0,0,0.35);
}
.card-info {
  padding: 50px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.card-tag {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--other-color);
  margin-bottom: 12px;
}
.card-info h2 {
  font-size: 2rem;
  margin-bottom: 18px;
}
.card-info ul {
  margin-bottom: 25px;
}
.card-info ul li {
  color: var(--other-color);
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.card-info ul li i {
  color: var(--main-color);
}
.view-case-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 22px;
  border-radius: 10px;
  background: #ffffff;
  color: #000000;
  font-weight: 600;
  font-size: 0.9rem;
  transition: 0.3s;
}
.view-case-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}
.card-img {
  padding: 35px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(circle at top, rgba(255,51,51,0.15), transparent 60%);
}
.card-img img {
  width: 100%;
  height: 330px;
  object-fit: cover;
  border-radius: 20px;
}

/* ===== CV ===== */
.cv-container {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 40px;
  padding: 150px 10% 80px;
  max-width: 1400px;
  margin: 0 auto;
}
.cv-sidebar {
  position: sticky;
  top: 120px;
  height: fit-content;
}
.cv-sidebar ul li {
  margin-bottom: 14px;
}
.cv-sidebar ul li a {
  color: var(--other-color);
  font-size: 0.9rem;
  font-weight: 500;
  padding: 8px 14px;
  border-left: 2px solid transparent;
  display: block;
  transition: 0.3s;
}
.cv-sidebar ul li a:hover {
  color: var(--main-color);
  border-left-color: var(--main-color);
  /* Background hover lebih halus dengan tint merah */
  background: rgba(139, 0, 0, 0.1);
  border-radius: 0 8px 8px 0;
}
.cv-content {
  /* Gradasi Gelap ke Merah Sangat Tua (Night Mode) */
  background: linear-gradient(145deg, rgba(34, 21, 21, 0.9) 0%, rgba(15, 10, 10, 0.95) 100%);
  border-radius: 24px;
  /* Border merah transparan agar terlihat 'menyala' tipis */
  border: 1px solid rgba(139, 0, 0, 0.3);
  padding: 50px;
  /* Shadow merah halus untuk kedalaman */
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.5), 0 0 15px rgba(139, 0, 0, 0.05);
  backdrop-filter: blur(10px);
}
.cv-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 35px;
  padding-bottom: 25px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
}
.cv-header h1 {
  font-size: 2.6rem;
  margin-bottom: 8px;
}
.cv-header p {
  color: var(--main-color);
  font-weight: 600;
}
.pdf-icon {
  font-size: 36px;
  color: var(--main-color);
  cursor: pointer;
}
.cv-section {
  margin-bottom: 40px;
}
.cv-section h2 {
  font-size: 1.7rem;
  margin-bottom: 20px;
  padding-left: 12px;
  border-left: 4px solid var(--main-color);
}
.basics-grid {
  display: grid;
  grid-template-columns: 150px 1fr;
  gap: 15px;
  /* Warna kotak info dasar: Putih transparan dengan tint merah */
  background: rgba(255, 255, 255, 0.03);
  padding: 25px;
  border-radius: 15px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}

body.light-mode .cv-sidebar ul li a:hover {
  background: rgba(139, 0, 0, 0.05);
}

body.light-mode .basics-grid {
  /* Kotak info di light mode: Merah pucat bersih */
  background: rgba(139, 0, 0, 0.02);
  border: 1px solid rgba(139, 0, 0, 0.08);
}

/* Penyesuaian Light Mode untuk CV */
body.light-mode .cv-content {
  /* Gradasi Putih ke Merah Sangat Muda */
  background: linear-gradient(145deg, #ffffff 0%, #fff5f5 100%);
  border: 1px solid rgba(139, 0, 0, 0.1);
  box-shadow: 0 20px 40px rgba(139, 0, 0, 0.05);
  color: #111;
}

.cv-sidebar ul li a {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.cv-content h2 {
  /* Memberikan sedikit glow pada judul section */
  text-shadow: 0 0 10px rgba(139, 0, 0, 0.2);
}

.basics-grid span:nth-child(odd) {
  font-weight: 600;
  color: var(--other-color);
}
.timeline-item {
  margin-bottom: 26px;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
}
.timeline-title {
  font-weight: 700;
}
.timeline-subtitle {
  color: var(--main-color);
  font-size: 0.95rem;
  margin-bottom: 6px;
  display: block;
}
/* Timeline Badge (Date) */
.timeline-date {
  background: var(--main-color); /* Merah marun kamu */
  color: #ffffff;               /* Ganti dari hitam ke putih */
  padding: 4px 14px;            /* Sedikit lebih lebar agar lega */
  border-radius: 20px;
  font-size: 0.8rem;
  font-weight: 700;             /* Tebalkan sedikit agar makin jelas */
  display: inline-block;
  box-shadow: 0 4px 12px rgba(139, 0, 0, 0.3); /* Shadow merah halus */
  letter-spacing: 0.5px;
}

/* Jika ingin transisi halus saat hover */
.timeline-item:hover .timeline-date {
  transform: scale(1.05);
  transition: 0.3s;
}

.timeline-content {
  color: var(--other-color);
  font-size: 0.9rem;
}
.timeline-content li {
  margin-left: 18px;
  list-style: disc;
  margin-bottom: 5px;
}
.skills-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}
.skill-cat h4 {
  margin-bottom: 10px;
  color: var(--main-color);
}
.skill-list {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* ===== Certifications ===== */
.cert-header {
  text-align: center;
  margin-bottom: 60px;
}
.cert-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.cert-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.cert-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 24px;
  max-width: 1200px;
  margin: 0 auto;
}
.cert-card {
  background: rgba(255,255,255,0.02);
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.15);
  padding: 26px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  transition: 0.3s;
}
.cert-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 16px 32px rgba(0,0,0,0.3);
}
.cert-img-box {
  width: 100%;
  height: 200px;
  border-radius: 16px;
  overflow: hidden;
  background: var(--second-bg-color);
}
.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: 0.4s;
}
.cert-card:hover .cert-img-box img {
  transform: scale(1.05);
}
.cert-info h3 {
  font-size: 1.4rem;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.cert-info h3 i {
  color: var(--main-color);
}
.cert-info p {
  color: var(--other-color);
  font-size: 0.95rem;
}

/* ===== Blog ===== */
.blog-header {
  text-align: center;
  margin-bottom: 60px;
}
.blog-header span {
  text-transform: uppercase;
  font-size: 0.75rem;
  letter-spacing: 4px;
  color: var(--main-color);
  font-weight: 600;
}
.blog-header h1 {
  font-size: 3rem;
  margin: 15px 0;
}
.blog-header p {
  color: var(--other-color);
}
.blog-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 26px;
  max-width: 1200px;
  margin: 0 auto;
}
.blog-card {
  background: #130b0b;
  border-radius: 24px;
  border: 1px solid rgba(255,51,51,0.18);
  padding: 38px;
  min-height: 320px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  position: relative;
  overflow: hidden;
  transition: 0.35s;
}
.blog-card::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,51,51,0.06) 0%, transparent 60%);
}
.blog-card h2 {
  font-size: 1.7rem;
  line-height: 1.3;
}
.blog-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 20px 40px rgba(0,0,0,0.35);
}
.blog-card:hover h2 {
  color: var(--main-color);
}
.blog-icon {
  width: 46px;
  height: 46px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
}

/* ===== Search Modal ===== */
.search-modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.8);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 1200;
}
.search-modal.active {
  display: flex;
}
.search-box {
  background: #1a1a1a;
  padding: 20px;
  border-radius: 12px;
  width: 90%;
  max-width: 420px;
}
.search-box input {
  width: 100%;
  padding: 10px 12px;
  border-radius: 6px;
  border: none;
  outline: none;
  margin-bottom: 12px;
}
.search-box ul li {
  margin-bottom: 6px;
}
.search-box ul li a {
  color: #ffffff;
  font-size: 0.95rem;
}

/* agar modal ikut light mode */
body.light-mode .search-box {
  background: #ffffff;
}
body.light-mode .search-box input {
  background: #f3f3f3;
  color: #111111;
}
body.light-mode .search-box ul li a {
  color: #111111;
}

/* =========================
   REPOSITORY PAGE STYLES
   ========================= */

.github-btn-center {
  display: flex;
  justify-content: center;
  margin-bottom: 60px;
}
.gh-profile-btn {
  padding: 12px 25px;
  background: var(--second-bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  color: var(--text-color);
  border-radius: 30px;
  font-size: 14px;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: 10px;
  transition: 0.3s;
}
.gh-profile-btn:hover {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* filter & search bar di halaman repository */
.repo-filters {
  background: var(--second-bg-color);
  padding: 30px;
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  align-items: center;
  margin-bottom: 50px;
}
.repo-filters .search-input {
  flex: 1;
  min-width: 250px;
  background: var(--bg-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 12px 20px;
  border-radius: 12px;
  color: var(--text-color);
  outline: none;
}
.repo-filters .filter-select {
  padding: 12px 15px;
  background: var(--bg-color);
  color: var(--text-color);
  border: 1px solid rgba(255, 51, 51, 0.15);
  border-radius: 12px;
  outline: none;
}
.repo-filters .reset-btn {
  padding: 12px 20px;
  border: 1px solid var(--main-color);
  color: var(--main-color);
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
  display: flex;
  align-items: center;
  gap: 6px;
}
.repo-filters .reset-btn:hover {
  background: var(--main-color);
  color: #ffffff;
}

/* repo grid / cards */
.repo-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 25px;
}
.repo-card {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 20px;
  border: 1px solid rgba(255, 51, 51, 0.15);
  padding: 30px;
  transition: 0.4s;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  min-height: 220px;
}
.repo-card:hover {
  transform: translateY(-8px);
  border-color: var(--main-color);
  box-shadow: 0 15px 30px rgba(255, 51, 51, 0.1);
}
.repo-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 1.1rem;
  font-weight: 700;
  margin-bottom: 15px;
  color: var(--text-color);
}
.repo-title i {
  color: var(--main-color);
}
.repo-desc {
  font-size: 14px;
  color: var(--other-color);
  line-height: 1.6;
  margin-bottom: 25px;
}
.repo-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  color: var(--other-color);
}
.lang-tag {
  padding: 4px 10px;
  background: var(--main-color);
  color: #ffffff;
  border-radius: 6px;
  font-weight: 700;
  font-size: 10px;
}

/* certification filters */
.cert-filters {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  justify-content: center;
  margin: 20px 0 40px;
}

.filter-tag {
  padding: 10px 18px;
  border-radius: 999px;
  border: 1px solid rgba(255, 51, 51, 0.2);
  background: var(--second-bg-color);
  color: var(--text-color);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
}

.filter-tag:hover,
.filter-tag.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* pagination buttons (certs + repo) */
.pagination-container {
  display: flex;
  justify-content: center;
  gap: 10px;
  margin: 30px 0 10px;
}

.page-btn {
  min-width: 40px;
  height: 40px;
  padding: 0 14px;
  border-radius: 10px;
  border: 1px solid rgba(255, 51, 51, 0.2);
  background: var(--second-bg-color);
  color: var(--text-color);
  font-weight: 600;
  cursor: pointer;
  transition: 0.3s;
}

.page-btn:hover,
.page-btn.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* light mode */
body.light-mode .filter-tag,
body.light-mode .page-btn {
  background: #ffffff;
  border-color: rgba(0, 0, 0, 0.08);
  color: #111111;
}

body.light-mode .filter-tag:hover,
body.light-mode .filter-tag.active,
body.light-mode .page-btn:hover,
body.light-mode .page-btn.active {
  background: var(--main-color);
  color: #ffffff;
  border-color: var(--main-color);
}

/* ===== Responsive ===== */
html {
  width: 100%;
  overflow-x: hidden;
}

body {
  width: 100%;
  overflow-x: hidden;
  line-height: 1.6;
}

img,
svg,
video {
  max-width: 100%;
  height: auto;
  display: block;
}

:where(section, .page-content, .cv-container) {
  width: 100%;
}

section {
  padding: clamp(90px, 10vw, 120px) clamp(4vw, 8vw, 10%) clamp(50px, 6vw, 80px);
}

.page-content,
.cv-container {
  padding-inline: clamp(4vw, 8vw, 10%);
}

.page-content {
  padding-top: clamp(110px, 12vw, 150px);
  max-width: 1400px;
  margin: 0 auto;
}

/* shared page headers */
.page-header,
.blog-header,
.cert-header,
.repo-header {
  text-align: center;
  margin-bottom: clamp(30px, 5vw, 60px);
}

.page-header h1,
.blog-header h1,
.cert-header h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  line-height: 1.1;
}

.page-header p,
.blog-header p,
.cert-header p {
  color: var(--other-color);
  max-width: 720px;
  margin: 0 auto;
}

/* navbar */
header,
header.sticky {
  padding-inline: clamp(16px, 4vw, 10%);
}

.logo {
  font-size: clamp(18px, 2vw, 24px);
}

.logo-box {
  width: 36px;
  height: 36px;
  font-size: 20px;
}

.navlist a {
  margin: 0 14px;
  white-space: nowrap;
}

.header-btns {
  gap: 12px;
}

.search-trigger {
  padding: 6px 12px;
  white-space: nowrap;
}

/* hero */
.hero {
  min-height: 100vh;
  padding-top: 120px;
}

.hero-wrapper {
  grid-template-columns: minmax(0, 1.15fr) minmax(0, 0.85fr);
  gap: clamp(24px, 4vw, 40px);
}

.hero-text h1 {
  font-size: clamp(2.4rem, 5vw, 4rem);
}

.hero-text p {
  max-width: 60ch;
}

.img-container {
  width: min(100%, 360px);
  aspect-ratio: 360 / 410;
  height: auto;
}

.img-outline {
  top: 24px;
  left: -24px;
}

.hero-stats {
  gap: 24px;
  flex-wrap: wrap;
}

/* grids/cards */
.box-grid,
.services-content,
.Portfolio-content,
.skills-container,
.cert-grid,
.blog-grid,
.repo-grid,
.skills-grid {
  width: 100%;
}

.box-grid,
.services-content,
.Portfolio-content {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

.skills-container {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 240px), 1fr));
}

.cert-grid,
.blog-grid {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

.repo-grid {
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 280px), 1fr));
}

/* portfolio */
.portfolio-container {
  width: 100%;
  gap: clamp(24px, 4vw, 40px);
}

.portfolio-card {
  grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
}

.card-info {
  padding: clamp(28px, 5vw, 50px);
}

.card-img {
  padding: clamp(20px, 4vw, 35px);
}

.card-img img {
  height: clamp(240px, 30vw, 330px);
  object-fit: cover;
}

/* CV */
.cv-container {
  grid-template-columns: minmax(220px, 260px) minmax(0, 1fr);
  gap: clamp(20px, 4vw, 40px);
}

.cv-content {
  padding: clamp(24px, 4vw, 50px);
}

.basics-grid {
  grid-template-columns: minmax(120px, 180px) minmax(0, 1fr);
}

.skills-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 20px;
}

/* certifications / blog / repo */
.cert-card,
.blog-card,
.repo-card {
  min-width: 0;
}

.cert-img-box {
  width: 100%;
  height: 200px;
  background: #f8f8f8;
  border-radius: 12px;
  overflow: hidden;
  cursor: zoom-in;
}

.cert-img-box img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  padding: 6px;
}

.blog-card {
  padding: clamp(24px, 4vw, 38px);
  min-height: 280px;
}

.repo-stats {
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 20px;
  max-width: 900px;
  padding: 0;
}

.repo-filters {
  padding: 24px;
}

.repo-filters .search-input {
  min-width: 0;
}

/* search / modal */
.search-box,
.modal-content {
  width: min(100%, 1000px);
}

.search-box {
  max-width: 420px;
}

.modal-body {
  padding: clamp(24px, 4vw, 50px);
}

.modal-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: clamp(20px, 4vw, 40px);
}

.tech-stack-container,
.tech-stack-img-container {
  flex-wrap: wrap;
}

.tech-logo-item {
  width: 42px;
  height: 42px;
}

/* footer */
.footer {
  padding-inline: clamp(16px, 4vw, 10%);
}

/* responsive breakpoints */
@media (max-width: 1200px) {
  .hero-wrapper {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .hero-text p {
    margin-inline: auto;
  }

  .hero-btns {
    justify-content: center;
  }

  .hero-img {
    order: -1;
    margin-bottom: 30px;
  }

  .social-float {
    display: none;
  }

  .hero-stats {
    justify-content: center;
  }

  .cv-container {
    grid-template-columns: 1fr;
  }

  .cv-sidebar {
    position: static;
    top: auto;
  }
}

@media (max-width: 950px) {
  #menu-icon {
    display: block;
  }

  .header-btns {
    margin-left: auto;
  }

  .navlist {
    position: fixed;
    top: 76px;
    right: -100%;
    width: min(86vw, 320px);
    height: calc(100vh - 76px);
    background: var(--second-bg-color);
    flex-direction: column;
    padding: 26px 20px;
    transition: 0.35s ease;
    overflow-y: auto;
    border-left: 1px solid rgba(255, 51, 51, 0.12);
  }

  .navlist.active {
    right: 0;
  }

  .navlist a {
    display: block;
    margin: 8px 0;
    padding: 10px 12px;
    border-radius: 10px;
  }

  .navlist a.active,
  .navlist a:hover {
    background: rgba(139, 0, 0, 0.12);
  }

  .repo-stats {
    grid-template-columns: 1fr;
  }

  .modal-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 768px) {
  :root {
    --h1-font: 3rem;
    --h2-font: 2.2rem;
    --p-font: 0.98rem;
  }

  header,
  header.sticky {
    padding-block: 14px;
  }

  .hero {
    padding-top: 110px;
  }

  .hero-stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    width: 100%;
  }

  .skills-grid,
  .basics-grid {
    grid-template-columns: 1fr;
  }

  .portfolio-card {
    grid-template-columns: 1fr;
  }

  .page-content,
  .cv-container,
  section {
    padding-left: 16px;
    padding-right: 16px;
  }

  .repo-filters {
    flex-direction: column;
    align-items: stretch;
  }

  .repo-filters .search-input,
  .repo-filters .filter-select,
  .repo-filters .reset-btn {
    width: 100%;
  }
}

@media (max-width: 640px) {
  .hero-text h1 {
    font-size: clamp(2.1rem, 10vw, 3rem);
  }

  .hero-stats {
    grid-template-columns: 1fr;
  }

  .contact {
    padding: 80px 16px 100px;
  }

  .social-links-minimal {
    flex-wrap: wrap;
    gap: 16px;
  }

  .blog-card {
    min-height: 240px;
  }

  .cert-card,
  .repo-card {
    padding: 22px;
  }

  .pagination-container {
    flex-wrap: wrap;
  }
}

@media (max-width: 480px) {
  .logo {
    font-size: 18px;
  }

  .logo-box {
    width: 32px;
    height: 32px;
    font-size: 18px;
  }

  .search-trigger .search-kb {
    display: none;
  }

  .hero-btns {
    flex-direction: column;
    gap: 14px;
  }

  .btn,
  .view-case-btn,
  .h-btn {
    width: 100%;
    justify-content: center;
  }

  .modal-body {
    padding: 20px;
  }
}

/* ===== Certification Lightbox ===== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.85);
  display: none;
  align-items: center;
  justify-content: center;
  z-index: 1300;
  opacity: 0;
  transition: 0.3s ease;
}

.modal-overlay.active {
  display: flex;
  opacity: 1;
}

.modal-img-zoom {
  max-width: min(90vw, 980px);
  max-height: 80vh;
  border-radius: 12px;
  box-shadow: 0 20px 50px rgba(0, 0, 0, 0.45);
}

.close-modal {
  position: absolute;
  top: 24px;
  right: 28px;
  font-size: 34px;
  color: #ffffff;
  cursor: pointer;
  transition: 0.2s ease;
  z-index: 1400;
}

.close-modal:hover {
  color: var(--main-color);
}

/* light mode */
body.light-mode .modal-overlay {
  background: rgba(0, 0, 0, 0.75);
}

